class Solution:
    def waysToSplit(self, nums):
        MOD = 10**9 + 7
        n = len(nums)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]
        total = prefix[n]
        count = 0
        for i in range(1, n - 1):
            left = prefix[i]
            for j in range(i + 1, n):
                mid = prefix[j] - prefix[i]
                right = total - prefix[j]
                if left <= mid <= right:
                    count += 1
        return count % MOD

