import bisect

class Solution:
    def waysToSplit(self, nums):
        MOD = 10**9 + 7
        n = len(nums)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]
        total = prefix[n]
        count = 0
        low = 2
        high = 2
        for i in range(1, n - 1):
            left = prefix[i]
            if low < i + 1:
                low = i + 1
            while low < n and prefix[low] < 2 * left:
                low += 1
            if high < low:
                high = low
            while high < n and 2 * prefix[high] <= total + left:
                high += 1
            # high is now the first index that fails; valid js are [low, high-1]
            if high - 1 >= low:
                count += (high - 1 - low + 1)
        return count % MOD

