var waysToSplit = function(nums) {
    const MOD = 1000000007;
    const n = nums.length;
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) prefix[i + 1] = prefix[i] + nums[i];
    const total = prefix[n];
    let count = 0;
    let low = 2;
    let high = 2;
    for (let i = 1; i < n - 1; i++) {
        const left = prefix[i];
        if (low < i + 1) low = i + 1;
        while (low < n && prefix[low] < 2 * left) low++;
        if (high < low) high = low;
        while (high < n && 2 * prefix[high] <= total + left) high++;
        if (high - 1 >= low) {
            count += (high - 1 - low + 1);
        }
    }
    return count % MOD;
};
